// CLX Copilot DB Query v1 — Validate admin token + parse
const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const token = body.token || null;
const question = body.question || '';
const panel_context = body.panel_context || 'unknown';

const masterToken = process.env.MARY_MASTER_TOKEN || 'TODO_SET_MARY_MASTER_TOKEN';
if (!token || masterToken === 'TODO_SET_MARY_MASTER_TOKEN' || token !== masterToken) {
  return { json: { _unauthorized: true, error: 'admin token required' } };
}
if (!question || String(question).trim().length === 0) {
  return { json: { _empty: true, error: 'question required' } };
}

return { json: { token, question, panel_context, _authorized: true } };

// CLX Copilot DB Query v1 — Parse Claude + safety validate SQL
const resp = $input.item.json || {};
const parsed = $('Validate + Parse').first().json;

let payload = null;
try {
  const text = (resp.content && resp.content[0] && resp.content[0].text) || '';
  payload = JSON.parse(text.trim());
} catch (e) {
  return { json: { _error: true, error: 'Claude response was not valid JSON', raw: (resp.content && resp.content[0] && resp.content[0].text) || null } };
}

const sql = (payload.sql_query || '').trim();
const upper = sql.toUpperCase();

// Safety checks (in-workflow defence; the RPC also enforces)
if (!upper.startsWith('SELECT') && !upper.startsWith('WITH')) {
  return { json: { _error: true, error: 'Generated SQL is not a SELECT/WITH' } };
}
if (/(\s|;|^)(INSERT|UPDATE|DELETE|DROP|ALTER|TRUNCATE|CREATE|GRANT|REVOKE)(\s|;|$)/i.test(sql)) {
  return { json: { _error: true, error: 'Generated SQL contains forbidden keyword' } };
}
if (!/LIMIT\s+\d+/i.test(sql)) {
  return { json: { _error: true, error: 'Generated SQL missing LIMIT clause' } };
}

return { json: {
  sql_query: sql,
  explanation: payload.explanation || '',
  result_type: payload.result_type || 'table',
  chart_hint: payload.chart_hint || null,
  panel_context: parsed.panel_context
} };

// CLX Copilot DB Query v1 — Build final response + log
const rpcResp = $input.item.json;
const parsed = $('Parse + Validate SQL').first().json;
const input = $('Validate + Parse').first().json;

let rows = [];
let ok = true;
let error = null;

if (Array.isArray(rpcResp)) rows = rpcResp;
else if (rpcResp && typeof rpcResp === 'object' && rpcResp.message) { ok = false; error = rpcResp.message; }
else if (rpcResp === null) rows = [];
else rows = rpcResp;

return { json: {
  ok,
  sql: parsed.sql_query,
  rows,
  explanation: parsed.explanation,
  result_type: parsed.result_type,
  chart_hint: parsed.chart_hint,
  error,
  panel_context: parsed.panel_context,
  question: input.question
} };
